def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (2 * k)) / (k ** 2 + 1)
            exp_component = np.exp(ratio / 2)
            priorities[i] = ratio ** 2 + penalty + exp_component
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 8):
                if j % 3 == 0:
                    continue
                sign = (-1) ** (j+1)
                term = sign * (ratio ** (j/2)) / (j + 1)
                score += term
            multiplier = 20 if ratio < 1.5 else 12
            priorities[i] = abs(score) * multiplier
            if 1.8 < ratio <= 2:
                extra = 0
                for m in range(2, 7):
                    extra += (ratio ** m) / (m * 2)
                priorities[i] += extra
        elif 0 < ratio <= 1:
            score = 0
            for n in range(1, 10):
                if n % 4 == 0:
                    sign = 1
                else:
                    sign = -1 if n % 2 == 0 else 1
                term = sign * (ratio ** n) / (n ** 1.5)
                score += term
            mult_factor = 18 if ratio < 0.25 else 13 if ratio < 0.5 else 7
            priorities[i] = abs(score) * mult_factor
            if ratio > 0.85:
                extra_score = 0
                for p in range(1, 5):
                    extra_score += ((-1) ** p) * (ratio ** (p / 2)) / (p + 2)
                priorities[i] += extra_score
        else:
            if item == 0:
                for r in range(3):
                    priorities[i] += r * capacity * 0.1
            else:
                priorities[i] = np.inf
    return priorities
